class Solution:
    def findIntegers(self, n: int) -> int:
        dp = [0] * (n + 1)
        dp[0] = 1
        dp[1] = 2
        for i in range(2, n + 1):
            dp[i] = dp[i - 1] + dp[i - 2]
            if bin(i).count("1") == bin(i - 1).count("1"):
                dp[i] -= dp[i - 2]
        return dp[n]
